def get_risk_from_confidence(confidence: dict) -> str:
    """Determine risk level based on confidence scores."""
    if isinstance(confidence, dict):
        scores = [confidence.get(k, 0) for k in ['factual', 'alignment', 'current', 'onwards'] if confidence.get(k)]
        min_score = min(scores) if scores else 0
    else:
        min_score = 0

    # Higher confidence = lower risk needed, but default to A
    # Tasks with 99%+ confidence are mission-critical (A++)
    # Tasks with 95%+ are important (A+)
    # Standard tasks are A
    if min_score >= 99:
        return "A++"
    elif min_score >= 95:
        return "A+"
    else:
        return "A"

def scan_file(filepath):
    """Scan a file for special Unicode characters."""
    findings = {
        'safe': defaultdict(list),
        'problematic': defaultdict(list),
        'unknown': defaultdict(list),
    }

    try:
        with open(filepath, 'r', encoding='utf-8') as f:
            for line_num, line in enumerate(f, 1):
                for char in line:
                    if ord(char) > 127:  # Non-ASCII
                        # Skip common safe chars
                        if char in '©®™°±²³¹º¼½¾':
                            continue
                        if char in '—–''""…':  # Typography
                            continue
                        if char in 'áàâäãåéèêëíìîïóòôöõúùûüýÿñçÁÀÂÄÃÅÉÈÊËÍÌÎÏÓÒÔÖÕÚÙÛÜÝŸÑÇ':
                            continue  # Accented chars

                        if char in SAFE_SINGLE_WIDTH:
                            findings['safe'][char].append((line_num, filepath))
                        elif char in PROBLEMATIC_EMOJI:
                            findings['problematic'][char].append((line_num, filepath))
                        elif char in VARIATION_SELECTORS:
                            findings['problematic'][char].append((line_num, filepath))
                        elif ord(char) > 0x1F000:  # Emoji range
                            findings['unknown'][char].append((line_num, filepath))
                        elif 0x2500 <= ord(char) <= 0x257F:  # Box drawing
                            findings['safe'][char].append((line_num, filepath))
                        elif 0x2580 <= ord(char) <= 0x259F:  # Block elements
                            findings['safe'][char].append((line_num, filepath))
                        elif 0x25A0 <= ord(char) <= 0x25FF:  # Geometric shapes
                            findings['safe'][char].append((line_num, filepath))
                        elif 0x2190 <= ord(char) <= 0x21FF:  # Arrows
                            findings['safe'][char].append((line_num, filepath))
                        elif 0x2700 <= ord(char) <= 0x27BF:  # Dingbats
                            findings['safe'][char].append((line_num, filepath))
    except (UnicodeDecodeError, PermissionError, IsADirectoryError):
        pass

    return findings

def main():
    root = Path(sys.argv[1]) if len(sys.argv) > 1 else Path('.')

    # Directories to skip
    skip_dirs = {'.git', 'node_modules', '__pycache__', '.venv', 'venv',
                 '.tools_venv', 'archive', '.collider'}

    # Extensions to scan
    scan_extensions = {'.md', '.py', '.js', '.yaml', '.yml', '.json', '.txt', '.html', '.css'}

    all_findings = []
    file_count = 0

    print(f"Scanning {root}...")

    for path in root.rglob('*'):
        if any(skip in path.parts for skip in skip_dirs):
            continue
        if path.is_file() and path.suffix in scan_extensions:
            findings = scan_file(path)
            if any(findings[k] for k in findings):
                all_findings.append(findings)
            file_count += 1

    print(f"Scanned {file_count} files.\n")
    print_report(all_findings)

def update_tdj():
    """Update the Temporal Daily Journal."""
    print("  Scanning filesystem for temporal data...")

    entries = []
    now = datetime.now()

    excluded = {".git", "__pycache__", "node_modules", ".venv", "archive", ".collider", ".collider-full"}

    for root, dirs, files in os.walk(REPO_ROOT):
        dirs[:] = [d for d in dirs if d not in excluded]

        for filename in files:
            filepath = Path(root) / filename
            rel_path = str(filepath.relative_to(REPO_ROOT))

            if any(excl in rel_path for excl in excluded):
                continue

            try:
                stat = filepath.stat()
                entries.append({
                    "path": rel_path,
                    "size": stat.st_size,
                    "mtime": stat.st_mtime,
                    "ctime": stat.st_ctime,
                    "scan_ts": now.timestamp()
                })
            except:
                continue

    # Write TDJ
    TDJ_PATH.parent.mkdir(parents=True, exist_ok=True)
    with open(TDJ_PATH, 'w') as f:
        f.write(json.dumps({
            "_meta": True,
            "version": "1.0.0",
            "type": "temporal_index",
            "project": "PROJECT_elements",
            "generated": now.isoformat(),
            "entry_count": len(entries),
            "scan_duration_ms": 0
        }) + '\n')
        for entry in entries:
            f.write(json.dumps(entry) + '\n')

    print(f"  Updated TDJ with {len(entries)} entries")
    return True

def find_latest_collider_output() -> Optional[Path]:
    """Find the most recent Collider output."""
    if not COLLIDER_OUTPUT_DIR.exists():
        return None
    outputs = list(COLLIDER_OUTPUT_DIR.glob("output_llm-oriented_*.json"))
    if not outputs:
        return None
    outputs.sort(key=lambda p: p.stat().st_mtime, reverse=True)
    return outputs[0]

def collider_output_age_minutes() -> float:
    """Get age of latest Collider output in minutes."""
    latest = find_latest_collider_output()
    if not latest:
        return float('inf')
    age_seconds = time.time() - latest.stat().st_mtime
    return age_seconds / 60

