class SmartWatcher:
    """File watcher with debouncing."""

    def __init__(self):
        self.last_change_time = 0
        self.pending = False
        self.last_mtime = self._get_max_mtime()

    def _should_ignore(self, path: Path) -> bool:
        """Check if path should be ignored."""
        path_str = str(path)
        return any(ignored in path_str for ignored in IGNORE_PATHS)

    def _get_max_mtime(self) -> float:
        """Get most recent modification time across watched paths."""
        max_mtime = 0
        for watch_path in WATCH_PATHS:
            if not watch_path.exists():
                continue

            for root, dirs, files in os.walk(watch_path):
                # Filter dirs to skip ignored paths
                dirs[:] = [d for d in dirs if not self._should_ignore(Path(root) / d)]

                for filename in files:
                    filepath = Path(root) / filename

                    if self._should_ignore(filepath):
                        continue

                    try:
                        mtime = filepath.stat().st_mtime
                        if mtime > max_mtime:
                            max_mtime = mtime
                    except (OSError, PermissionError):
                        continue

        return max_mtime

    def check_for_changes(self):
        """Check if files changed since last check."""
        current_mtime = self._get_max_mtime()

        if current_mtime > self.last_mtime:
            # Files changed!
            self.last_change_time = time.time()
            self.last_mtime = current_mtime
            self.pending = True
            print(f"[{datetime.now().strftime('%H:%M:%S')}] File changes detected, starting quiet period...")

    def check_and_trigger(self):
        """Trigger wire if quiet period elapsed."""
        if not self.pending:
            return

        quiet_time = time.time() - self.last_change_time

        if quiet_time >= QUIET_PERIOD_SECONDS:
            print(f"[{datetime.now().strftime('%H:%M:%S')}] Quiet for {QUIET_PERIOD_SECONDS}s, running wire...")

            # Run wire --quick
            try:
                result = subprocess.run(
                    [sys.executable, str(REPO_ROOT / ".agent" / "tools" / "wire.py"), "--quick"],
                    cwd=str(REPO_ROOT),
                    capture_output=True,
                    text=True,
                    timeout=600
                )

                if result.returncode == 0:
                    print(f"[{datetime.now().strftime('%H:%M:%S')}] Wire completed successfully")
                else:
                    print(f"[{datetime.now().strftime('%H:%M:%S')}] Wire failed: {result.stderr[:200]}")

            except subprocess.TimeoutExpired:
                print(f"[{datetime.now().strftime('%H:%M:%S')}] Wire timed out")
            except Exception as e:
                print(f"[{datetime.now().strftime('%H:%M:%S')}] Wire error: {e}")

            self.pending = False
            # Reset mtime to avoid re-triggering immediately
            self.last_mtime = self._get_max_mtime()

    def run(self):
        """Main watch loop."""
        print(f"[{datetime.now().strftime('%H:%M:%S')}] Filesystem watcher started")
        print(f"  Watching: {', '.join(str(p.name) for p in WATCH_PATHS)}")
        print(f"  Quiet period: {QUIET_PERIOD_SECONDS}s")
        print(f"  Check interval: {CHECK_INTERVAL_SECONDS}s")
        print()

        try:
            while True:
                self.check_for_changes()
                self.check_and_trigger()
                time.sleep(CHECK_INTERVAL_SECONDS)

        except KeyboardInterrupt:
            print(f"\n[{datetime.now().strftime('%H:%M:%S')}] Watcher stopped")

